pub fn capacity(&self, max_buffer_size: usize) -> WindowSize {
    let available = self.send_flow.available().as_size() as usize;
    let buffered = self.buffered_send_data;

    available.min(max_buffer_size).saturating_sub(buffered) as WindowSize
}

fn calc_max_continuation_frames(header_max: usize, frame_max: usize) -> usize {
    // At least this many frames needed to use max header list size
    let min_frames_for_list = (header_max / frame_max).max(1);
    // Some padding for imperfectly packed frames
    // 25% without floats
    let padding = min_frames_for_list >> 2;
    min_frames_for_list.saturating_add(padding).max(5)
}

pub fn new(src: &[u8]) -> Result<AllocatedExtension, InvalidMethod> {
    let mut data: Vec<u8> = vec![0; src.len()];

    write_checked(src, &mut data)?;

    // Invariant: data is exactly src.len() long and write_checked
    // ensures that the first src.len() bytes of data are valid UTF-8.
    Ok(AllocatedExtension(data.into_boxed_slice()))
}

pub(crate) fn set_write_strategy_queue(&mut self) {
    // this should always be called only at construction time,
    // so this assert is here to catch myself
    debug_assert_eq!(self.write_buf.queue.bufs_cnt(), 0);
    self.write_buf.set_strategy(WriteStrategy::Queue);
}

pub(crate) fn set_write_strategy_flatten(&mut self) {
    // this should always be called only at construction time,
    // so this assert is here to catch myself
    debug_assert_eq!(self.write_buf.queue.bufs_cnt(), 0);
    self.write_buf.set_strategy(WriteStrategy::Flatten);
}

fn parse_rsa_pub_key(key: &[u8]) -> Result<RsaPublicKey, Error> {
    let pem = std::str::from_utf8(key).map_err(Error::protocol)?;

    // This takes advantage of the knowledge that we know
    // we are receiving a PKCS#8 RSA Public Key at all
    // times from MySQL

    RsaPublicKey::from_public_key_pem(pem).map_err(Error::protocol)
}

fn kind(&self) -> ErrorKind {
    match self.code {
        SQLITE_CONSTRAINT_UNIQUE | SQLITE_CONSTRAINT_PRIMARYKEY => ErrorKind::UniqueViolation,
        SQLITE_CONSTRAINT_FOREIGNKEY => ErrorKind::ForeignKeyViolation,
        SQLITE_CONSTRAINT_NOTNULL => ErrorKind::NotNullViolation,
        SQLITE_CONSTRAINT_CHECK => ErrorKind::CheckViolation,
        _ => ErrorKind::Other,
    }
}

fn create_schema_if_not_exists<'e>(
    &'e mut self,
    schema_name: &'e str,
) -> BoxFuture<'e, Result<(), MigrateError>> {
    Box::pin(async {
        self.get_migrate()?
            .create_schema_if_not_exists(schema_name)
            .await
    })
}

pub async fn listen(&mut self, channel: &str) -> Result<(), Error> {
    self.connection()
        .await?
        .execute(AssertSqlSafe(format!(r#"LISTEN "{}""#, ident(channel))))
        .await?;

    self.channels.push(channel.to_owned());

    Ok(())
}

fn from(package: &MetadataPackage) -> Self {
    let name = package.name.clone();
    let src_paths = package
        .targets
        .iter()
        .map(|target| target.src_path.clone().into_std_path_buf())
        .collect();

    Self { name, src_paths }
}

fn load(self, el: &crate::renderer::types::Element) {
    // safe to construct SendWrapper here, because it will only run in the browser
    // so it will always be accessed or dropped from the main thread
    self.0
        .set(Some(SendWrapper::new(el.clone().unchecked_into())));
}

fn tuple_of_static_matches() {
    let path = "/foo/bar";
    let def = (StaticSegment("foo"), StaticSegment("bar"));
    let matched = def.test(path).expect("couldn't match route");
    assert_eq!(matched.matched(), "/foo/bar");
    assert_eq!(matched.remaining(), "");
    let params = matched.params();
    assert!(params.is_empty());
}

fn handle_bevy_event(
    mut counter_event_reader: EventReader<CounterEvtData>,
    mut cube_query: Query<&mut Transform, With<Cube>>,
) {
    let mut cube_transform = cube_query.get_single_mut().expect("no cube :(");
    for _ev in counter_event_reader.read() {
        cube_transform.translation += Vec3::new(0.0, _ev.value, 0.0);
    }
}

fn matching_after_optional_param() {
    let path = "/bar";
