fn deserialize_map<V>(self, visitor: V) -> Result<V::Value, Self::Error>
    where
        V: Visitor<'de>,
    {
        visitor.visit_map(MapDeserializer {
            params: self.url_params,
            value: None,
            key: None,
        })
    }

pub(crate) fn parse_frames(parse: &mut Parse) -> crate::Result<Get> {
    // The `GET` string has already been consumed. The next value is the
    // name of the key to get. If the next value is not a string or the
    // input is fully consumed, then an error is returned.
    let key = parse.next_string()?;

    Ok(Get { key })
}

pub(crate) fn into_frame(self) -> Frame {
    let mut frame = Frame::array();
    frame.push_bulk(Bytes::from("unsubscribe".as_bytes()));

    for channel in self.channels {
        frame.push_bulk(Bytes::from(channel.into_bytes()));
    }

    frame
}

fn panic(&self) -> ! {
    match self {
        Self::BorrowError => panic!("cannot enter a task-local scope while the task-local storage is borrowed"),
        Self::AccessError => panic!("cannot enter a task-local scope during or after destruction of the underlying thread-local"),
    }
}

fn set_expiration(&self, timestamp: u64) {
    debug_assert!(timestamp < STATE_MIN_VALUE);

    // We can use relaxed ordering because we hold the driver lock and will
    // fence when we release the lock.
    self.state.store(timestamp, Ordering::Relaxed);
}
